#pragma OPENCL EXTENSION cl_kfp_printf : enable

kernel sum_weights_kernel(
    global double * weights,
    global double * partial_sums,
    const int Nparticles)
{
    int x = get_global_id(0);
    if (x < Nparticles) {
        partial_sums[x] = weights[x];
    }
    if (x == 0) {
        double sum = 0.0;
        for (int i = 0; i < Nparticles; i++) {
            sum += weights[i];
        }
        partial_sums[Nparticles] = sum;
    }
}

kernel normalize_weights_kernel(
    global double * weights,
    global double * CDF,
    global double * u,
    global int * seed,
    const int Nparticles,
    const double sumWeights)
{
    int x = get_global_id(0);
    if (x < Nparticles) {
        weights[x] = weights[x] / sumWeights;
        if (x == 0) {
            CDF[0] = weights[0];
        } else {
            CDF[x] = weights[x] + CDF[x - 1];
        }
    }
    if (x == 0) {
        double u1 = (1.0 / ((double)(Nparticles))) * randu(seed, 0);
        for (int i = 0; i < Nparticles; i++) {
            u[i] = u1 + i / ((double)(Nparticles));
        }
    }
}

kernel compute_weighted_average_kernel(
    global double * arrayX,
    global double * arrayY,
    global double * weights,
    global double * xe_ye,
    const int Nparticles)
{
    int x = get_global_id(0);
    if (x < Nparticles) {
        xe_ye[0] += arrayX[x] * weights[x];
        xe_ye[1] += arrayY[x] * weights[x];
    }
}

