#pragma OPENCL EXTENSION cl_kfp_printf : enable

int findIndex(global double * CDF, int lengthCDF, double value) {
    int index = -1;
    for (int x = 0; x < lengthCDF; x++) {
        if (CDF[x] >= value) {
            index = x;
            break;
        }
    }
    if (index == -1) {
        return lengthCDF - 1;
    }
    return index;
}

kernel find_index_kernel(
    global double * arrayX,
    global double * arrayY,
    global double * CDF,
    global double * u,
    global double * xj,
    global double * yj,
    global double * weights,
    const int Nparticles)
{
    int j = get_global_id(0);
    if (j < Nparticles) {
        int i = findIndex(CDF, Nparticles, u[j]);
        if (i == -1)
            i = Nparticles - 1;
        xj[j] = arrayX[i];
        yj[j] = arrayY[i];
    }
}

kernel resample_particles_kernel(
    global double * arrayX,
    global double * arrayY,
    global double * xj,
    global double * yj,
    global double * weights,
    const int Nparticles)
{
    int x = get_global_id(0);
    if (x < Nparticles) {
        arrayX[x] = xj[x];
        arrayY[x] = yj[x];
        weights[x] = 1.0 / ((double)(Nparticles));
    }
}
